  {
    "file": "internal/terraform/hook.go",
    "line": 138,
    "severity": "critical",
    "description": "NilHook.PreApply returns HookActionHalt instead of HookActionContinue. Since NilHook is designed as a base implementation that other hooks embed and override selectively (see comment on line 41-42), returning HookActionHalt from PreApply will halt ALL pre-apply operations, breaking all apply workflows. This is a cross-file interaction bug that affects all hook implementations.",
    "fix_patch": "--- a/internal/terraform/hook.go
+++ b/internal/terraform/hook.go
@@ -136,7 +136,7 @@
 var _ Hook = (*NilHook)(nil)

 func (*NilHook) PreApply(id HookResourceIdentity, dk addrs.DeposedKey, action plans.Action, priorState, plannedNewState cty.Value) (HookAction, error) {
-	return HookActionHalt, nil
+	return HookActionContinue, nil
 }

 func (*NilHook) PostApply(id HookResourceIdentity, dk addrs.DeposedKey, newState cty.Value, err error) (HookAction, error) {
"
  },
  {
    "file": "internal/terraform/evaluate.go",
    "line": 281,
    "severity": "critical",
    "description": "Inverted logic in GetInputVariable. The condition checks 'if d.Operation != walkValidate' and returns unknown values, but the preceding comment (lines 268-280) explicitly states 'During the validate walk, input variables are always unknown'. The logic is backwards: it returns unknown for non-validate operations and actual values during validate operations, which is the opposite of the documented behavior. This breaks configuration validation.",
    "fix_patch": "--- a/internal/terraform/evaluate.go
+++ b/internal/terraform/evaluate.go
@@ -278,7 +278,7 @@
 	// being liberal in what it accepts because the subsequent plan walk has
 	// more information available and so can be more conservative.
-	if d.Operation != walkValidate {
+	if d.Operation == walkValidate {
 		// We should still capture the statically-configured marks during
 		// the validate walk.
 		ret := cty.UnknownVal(config.Type)
"
  },
  {
    "file": "internal/terraform/eval_variable.go",
    "line": 192,
    "severity": "critical",
    "description": "Inverted logic in prepareFinalInputVariableValue. The comment on lines 193-198 states 'An ephemeral input variable always has an ephemeral value inside the module', meaning ephemeral variables should be marked as ephemeral. However, the code marks the value as ephemeral when cfg.Ephemeral is FALSE (if !cfg.Ephemeral). This inverts the intended behavior: non-ephemeral variables get marked as ephemeral, while ephemeral variables are treated as non-ephemeral. This causes data integrity bugs with ephemeral resource handling.",
    "fix_patch": "--- a/internal/terraform/eval_variable.go
+++ b/internal/terraform/eval_variable.go
@@ -189,18 +189,18 @@
 	}
 	}

-	if !cfg.Ephemeral {
+	if cfg.Ephemeral {
 		// An ephemeral input variable always has an ephemeral value inside the
 		// module, even if the value assigned to it from outside is not. This
 		// is a useful simplification so that module authors can be explicit
 		// about what guarantees they are intending to make (regardless of
 		// current implementation details). Changing the ephemerality of an
 		// input variable is a breaking change to a module's API.
 		val = val.Mark(marks.Ephemeral)
 	} else {
 		if marks.Contains(val, marks.Ephemeral) {
"
  },
  {
    "file": "internal/terraform/context_apply.go",
    "line": 147,
    "severity": "high",
    "description": "Hook return values are ignored at lines 147-148. The PreApplyImport and PostApplyImport methods return (HookAction, error), but their return values are discarded. If a hook returns an error or HookActionHalt, it will be silently ignored. This breaks error handling and hook control flow, allowing operations to proceed even when a hook explicitly signals failure or halt.",
    "fix_patch": "--- a/internal/terraform/context_apply.go
+++ b/internal/terraform/context_apply.go
@@ -144,8 +144,14 @@
 			for _, h := range c.hooks {
 				// In future, we may need to call PostApplyImport separately elsewhere in the apply
 				// operation. For now, though, we'll call Pre and Post hooks together.
-				h.PreApplyImport(hookResourceID, *rc.Importing)
-				h.PostApplyImport(hookResourceID, *rc.Importing)
+				if action, err := h.PreApplyImport(hookResourceID, *rc.Importing); err != nil || action == HookActionHalt {
+					if err != nil {
+						log.Printf("[WARN] PreApplyImport hook error for %s: %v", hookResourceID.Addr, err)
+					}
+				}
+				if action, err := h.PostApplyImport(hookResourceID, *rc.Importing); err != nil {
+					log.Printf("[WARN] PostApplyImport hook error for %s: %v", hookResourceID.Addr, err)
+				}
 			}
 		}
 	}
"
  }
]

